mapper.sql:
WHERE va.deleted = 0

    AND (sp.student_no LIKE CONCAT('%', #{query.studentKeyword}, '%')
      OR sp.chinese_name LIKE CONCAT('%', #{query.studentKeyword}, '%')
      OR sp.english_name LIKE CONCAT('%', #{query.studentKeyword}, '%'))


    AND va.alert_type = #{query.alertType}


    AND va.alert_level = #{query.alertLevel}


    AND va.alert_status = #{query.alertStatus}


    AND va.target_type = #{query.targetType}

mapper.select:
SELECT COUNT(1)
FROM visa_compliance_alert
WHERE deleted = 0
  AND target_type = #{targetType}
  AND target_id = #{targetId}
  AND alert_type = #{alertType}
  AND alert_status IN ('OPEN', 'PROCESSING')
